    planesData: { plan: string; objetivo: string; }[];
}

// Initialize the GoogleGenAI client.
// The API key is automatically sourced from the `process.env.API_KEY` environment variable.
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

// List of models to attempt in order of preference.
// Using robust models for complex educational context generation.
const modelsToTry = [
    'gemini-3-pro-preview',
    'gemini-3-flash-preview',
];

export const generatePmeActions = async (params: PmeActionParams): Promise<string> => {
    const { cantidad, dimension, subdimension, objEstrategico, planesData } = params;

    const planesTextoPrompt = planesData
        .map(p => `- Plan: "${p.plan}" | Objetivo: "${p.objetivo}"`)
        .join("\n            ");

    const promptText = `
        Actúa como un experto asesor educacional en Chile, especializado en PME y Estándares Indicativos de Desempeño.
        Tu tarea es diseñar ${cantidad} propuesta(s) de acción(es) concreta(s) para un Plan de Mejoramiento Educativo.

        DATOS DE CONTEXTO:
        1. Dimensión PME: ${dimension}
        2. Subdimensión PME: ${subdimension}
        3. Objetivo Estratégico PME: "${objEstrategico || 'No especificado'}"

        ARTICULACIÓN NORMATIVA REQUERIDA (Integrar estos planes y objetivos):
        ${planesTextoPrompt}

        INSTRUCCIONES DE DISEÑO:
        Genera ${cantidad} acción(es) distinta(s). Si hay 2 planes seleccionados, intenta que la acción los integre a ambos o genera acciones que aborden la convergencia de ambos.

        Formato obligatorio para cada acción:
        ### Nombre de la Acción: [Nombre técnico y motivador]
        * **Vinculación Normativa:** Explica explícitamente cómo esta acción responde a los objetivos seleccionados de los planes (${planesData.map(p => p.plan).join(' y ')}).
        * **Descripción:** Paso a paso breve de la implementación.
        * **Recursos Clave:** Humanos, materiales o financieros.
        * **Medio de Verificación:** Documento que evidencia la ejecución.
    `;

    let lastError: Error | null = null;

    for (const modelName of modelsToTry) {
        try {
            console.log(`Intentando conectar con modelo: ${modelName}`);
            const response: GenerateContentResponse = await ai.models.generateContent({
                model: modelName,
                contents: [{ parts: [{ text: promptText }] }],
                // Safety settings to prevent blocking for educational topics like sexuality
                safetySettings: [
                    { category: "HARM_CATEGORY_HARASSMENT", threshold: "BLOCK_ONLY_HIGH" },
                    { category: "HARM_CATEGORY_HATE_SPEECH", threshold: "BLOCK_ONLY_HIGH" },
                    { category: "HARM_CATEGORY_SEXUALLY_EXPLICIT", threshold: "BLOCK_ONLY_HIGH" },
                    { category: "HARM_CATEGORY_DANGEROUS_CONTENT", threshold: "BLOCK_ONLY_HIGH" }
                ]
            });

            const text = response.text;
            if (text) {
                console.log(`Éxito con modelo: ${modelName}`);
                return text;
            }

            // Handle cases where the response is empty or blocked
            const finishReason = response.candidates?.[0]?.finishReason;
            if (finishReason === 'SAFETY') {
                throw new Error("La respuesta fue bloqueada por filtros de seguridad. Intenta reformular el objetivo evitando términos muy explícitos.");
            }
             if (finishReason === 'RECITATION') {
                throw new Error("La respuesta fue bloqueada por ser similar a una fuente protegida. Intenta reformular el objetivo.");
            }

            throw new Error('La IA devolvió una respuesta vacía.');

        } catch (error) {
            console.error(`Error con el modelo ${modelName}:`, error);
            lastError = error as Error;
        }
    }

    if (lastError?.message.includes('API key not valid')) {
       throw new Error("ERROR DE API KEY: La clave de API no es válida. Por favor, asegúrate de que esté configurada correctamente.");
    }

    if (lastError?.message.includes('permission')) {
         throw new Error("ERROR DE PERMISOS: La clave de API no tiene los permisos necesarios. Verifica que la 'Generative Language API' esté habilitada en tu proyecto de Google Cloud.");
    }

    throw lastError || new Error("Todos los modelos de IA fallaron. Por favor, inténtalo de nuevo más tarde.");
};

