                // Clean up response, remove potential markdown like quotes
                return text.trim().replace(/^"/, '').replace(/"$/, '');
            }

            throw new Error('La IA devolvió una sugerencia vacía.');
        } catch (error) {
            console.error(`Error con el modelo ${modelName}:`, error);
