        }
    }

    throw lastError || new Error("Todos los modelos de IA fallaron al generar la sugerencia.");
};


export const generatePmeActions = async (params: PmeActionParams): Promise<string> => {
    const { cantidad, dimension, subdimension, objEstrategico, estrategia, planesData } = params;

    const planesTextoPrompt = planesData
        .map(p => `- Plan: "${p.plan}" | Objetivo: "${p.objetivo}"`)
        .join("\n            ");

    const promptText = `
        Actúa como un experto asesor educacional en Chile, especializado en PME y Estándares Indicativos de Desempeño.
        Tu tarea es diseñar ${cantidad} propuesta(s) de acción(es) concreta(s) para un Plan de Mejoramiento Educativo.

        DATOS DE CONTEXTO:
        1. Dimensión PME: ${dimension}
        2. Subdimensión PME: ${subdimension}
        3. Objetivo Estratégico PME: "${objEstrategico || 'No especificado'}"
        4. Estrategia General a seguir: "${estrategia}"

        ARTICULACIÓN NORMATIVA REQUERida (Integrar estos planes y objetivos):
        ${planesTextoPrompt}

        INSTRUCCIONES DE DISEÑO:
        Genera ${cantidad} acción(es) distinta(s) que sean coherentes con la Estrategia General definida. Si hay 2 planes seleccionados, intenta que la acción los integre a ambos o genera acciones que aborden la convergencia de ambos.

        Formato obligatorio para cada acción:
        ### Nombre de la Acción: [Nombre técnico y motivador]
        * **Vinculación Normativa:** Explica explícitamente cómo esta acción responde a los objetivos seleccionados de los planes (${planesData.map(p => p.plan).join(' y ')}).
        * **Descripción:** Paso a paso breve de la implementación.
        * **Recursos Clave:** Humanos, materiales o financieros.
        * **Medio de Verificación:** Documento que evidencia la ejecución.
    `;

    let lastError: Error | null = null;

    for (const modelName of modelsToTry) {
        try {
            console.log(`Intentando conectar con modelo: ${modelName}`);
            const response: GenerateContentResponse = await ai.models.generateContent({
                model: modelName,
                contents: [{ parts: [{ text: promptText }] }],
                // Safety settings to prevent blocking for educational topics like sexuality
                safetySettings: [
                    { category: "HARM_CATEGORY_HARASSMENT", threshold: "BLOCK_ONLY_HIGH" },
                    { category: "HARM_CATEGORY_HATE_SPEECH", threshold: "BLOCK_ONLY_HIGH" },
                    { category: "HARM_CATEGORY_SEXUALLY_EXPLICIT", threshold: "BLOCK_ONLY_HIGH" },
                    { category: "HARM_CATEGORY_DANGEROUS_CONTENT", threshold: "BLOCK_ONLY_HIGH" }
                ]
            });

            const text = response.text;
            if (text) {
                console.log(`Éxito con modelo: ${modelName}`);
                return text;
            }

            // Handle cases where the response is empty or blocked
            const finishReason = response.candidates?.[0]?.finishReason;
            if (finishReason === 'SAFETY') {
                throw new Error("La respuesta fue bloqueada por filtros de seguridad. Intenta reformular el objetivo evitando términos muy explícitos.");
            }
             if (finishReason === 'RECITATION') {
                throw new Error("La respuesta fue bloqueada por ser similar a una fuente protegida. Intenta reformular el objetivo.");
            }

            throw new Error('La IA devolvió una respuesta vacía.');

        } catch (error) {
            console.error(`Error con el modelo ${modelName}:`, error);
            lastError = error as Error;
        }
    }

    if (lastError?.message.includes('API key not valid')) {
       throw new Error("ERROR DE API KEY: La clave de API no es válida. Por favor, asegúrate de que esté configurada correctamente.");
    }

    if (lastError?.message.includes('permission')) {
         throw new Error("ERROR DE PERMISOS: La clave de API no tiene los permisos necesarios. Verifica que la 'Generative Language API' esté habilitada en tu proyecto de Google Cloud.");
    }

    throw lastError || new Error("Todos los modelos de IA fallaron. Por favor, inténtalo de nuevo más tarde.");
};

import React, { useState, useMemo } from 'react';
import { dataMap, objetivosNormativos, Plan } from './constants';
import { generatePmeActions, generateStrategicObjectiveSuggestion, generateEstrategia } from './services/geminiService';
import type { Message } from './types';
import MessageBox from './components/MessageBox';
import Spinner from './components/Spinner';

export default function App() {
    const [dimension, setDimension] = useState<string>('');
    const [subdimension, setSubdimension] = useState<string>('');
    const [objEstrategico, setObjEstrategico] = useState<string>('');
    const [estrategia, setEstrategia] = useState<string>('');
    const [selectedPlanes, setSelectedPlanes] = useState<string[]>([]);
    const [selectedPlanObjectives, setSelectedPlanObjectives] = useState<Record<string, string>>({});
    const [cantidad, setCantidad] = useState<number>(1);

    const [isLoading, setIsLoading] = useState<boolean>(false);
    const [isGeneratingObjective, setIsGeneratingObjective] = useState<boolean>(false);
    const [isGeneratingEstrategia, setIsGeneratingEstrategia] = useState<boolean>(false);
    const [result, setResult] = useState<string>('');
    const [message, setMessage] = useState<Message | null>(null);

    const subdimensiones = useMemo(() => {
        if (dimension && dataMap[dimension as keyof typeof dataMap]) {
            return dataMap[dimension as keyof typeof dataMap];
        }
        return [];
    }, [dimension]);

    const handleDimensionChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
        const newDimension = e.target.value;
        setDimension(newDimension);
        setSubdimension('');
    };

    const handlePlanSelection = (e: React.ChangeEvent<HTMLInputElement>) => {
        const { value, checked } = e.target;
        setMessage(null);
        let newSelectedPlanes = [...selectedPlanes];

        if (checked) {
            if (selectedPlanes.length < 2) {
                newSelectedPlanes.push(value);
            } else {
                e.target.checked = false;
                setMessage({ type: 'error', text: 'Solo puedes seleccionar un máximo de 2 planes normativos para articular.' });
                return;
            }
        } else {
            newSelectedPlanes = newSelectedPlanes.filter(plan => plan !== value);
            const newObjectives = { ...selectedPlanObjectives };
            delete newObjectives[value];
            setSelectedPlanObjectives(newObjectives);
        }
        setSelectedPlanes(newSelectedPlanes);
    };

    const handleObjectiveChange = (planName: string, value: string) => {
        setSelectedPlanObjectives(prev => ({
            ...prev,
            [planName]: value
        }));
    };

    const handleGenerateStrategicObjective = async () => {
        setMessage(null);
        if (!subdimension) {
            setMessage({ type: 'error', text: 'Por favor, selecciona una subdimensión primero.' });
            return;
        }
        if (selectedPlanes.length === 0) {
             setMessage({ type: 'error', text: 'Por favor, selecciona al menos un plan normativo.' });
            return;
        }

        const missingObjective = selectedPlanes.some(plan => !selectedPlanObjectives[plan]);
        if (missingObjective) {
            setMessage({ type: 'error', text: 'Por favor selecciona un objetivo específico para cada plan marcado antes de generar una sugerencia.' });
            return;
        }

        const planesData = selectedPlanes.map(plan => ({
            plan,
            objetivo: selectedPlanObjectives[plan]
        }));

        setIsGeneratingObjective(true);
        try {
            const suggestion = await generateStrategicObjectiveSuggestion({
                dimension,
                subdimension,
                planesData,
            });
            setObjEstrategico(suggestion);
        } catch (error) {
             console.error(error);
             const errorMessage = (error as Error).message || 'Ocurrió un error desconocido.';
             setMessage({ type: 'error', text: `Error al generar sugerencia:\n${errorMessage}` });
        } finally {
            setIsGeneratingObjective(false);
        }
    };

    const handleGenerateEstrategia = async () => {
        setMessage(null);
        if (!subdimension || !objEstrategico) {
            setMessage({ type: 'error', text: 'Por favor, selecciona una subdimensión y define un objetivo estratégico primero.' });
            return;
        }
        if (selectedPlanes.length === 0) {
            setMessage({ type: 'error', text: 'Por favor, selecciona al menos un plan normativo para generar la estrategia.' });
            return;
        }
        const missingObjective = selectedPlanes.some(plan => !selectedPlanObjectives[plan]);
        if (missingObjective) {
            setMessage({ type: 'error', text: 'Por favor selecciona un objetivo para cada plan normativo antes de generar la estrategia.' });
            return;
        }

        const planesData = selectedPlanes.map(plan => ({
            plan,
            objetivo: selectedPlanObjectives[plan]
        }));

        setIsGeneratingEstrategia(true);
        try {
            const suggestion = await generateEstrategia({ dimension, subdimension, objEstrategico, planesData });
            setEstrategia(suggestion);
        } catch (error) {
             console.error(error);
             const errorMessage = (error as Error).message || 'Ocurrió un error desconocido.';
             setMessage({ type: 'error', text: `Error al generar estrategia:\n${errorMessage}` });
        } finally {
            setIsGeneratingEstrategia(false);
        }
    };

    const isEstrategiaButtonDisabled = useMemo(() => {
        return isGeneratingEstrategia || 
               !objEstrategico || 
               !subdimension || 
               selectedPlanes.length === 0 || 
               selectedPlanes.some(plan => !selectedPlanObjectives[plan]);
    }, [isGeneratingEstrategia, objEstrategico, subdimension, selectedPlanes, selectedPlanObjectives]);


    const generarPropuesta = async () => {
        setMessage(null);
        setResult('');

        if (!dimension || !subdimension) {
            setMessage({ type: 'error', text: 'Falta seleccionar Dimensión y Subdimensión.' });
            return;
        }

        if (!estrategia) {
             setMessage({ type: 'error', text: 'Por favor, genera una estrategia antes de crear las acciones.' });
            return;
        }

        if (selectedPlanes.length === 0) {
            setMessage({ type: 'error', text: 'Selecciona al menos un Plan Normativo.' });
            return;
        }

        const missingObjective = selectedPlanes.some(plan => !selectedPlanObjectives[plan]);
        if (missingObjective) {
            setMessage({ type: 'error', text: 'Por favor selecciona un objetivo específico para cada plan marcado.' });
            return;
        }

        const planesData = selectedPlanes.map(plan => ({
            plan,
            objetivo: selectedPlanObjectives[plan] === "Otro" ? "Objetivo específico a definir por la IA según contexto" : selectedPlanObjectives[plan]
        }));

        setIsLoading(true);

        try {
            const generatedText = await generatePmeActions({
                cantidad,
                dimension,
                subdimension,
                objEstrategico,
                estrategia,
                planesData,
            });

            const formattedText = generatedText
                .replace(/\*\*(.*?)\*\*/g, '<strong>$1</strong>')
                .replace(/### (.*)/g, '<h3 class="text-pme-accent mt-5 border-b border-gray-200 pb-2 mb-3">$1</h3>')
                .replace(/^\* (.*)/gm, '<li class="ml-5 list-disc">$1</li>');

            setResult(formattedText);

        } catch (error) {
            console.error(error);
            const errorMessage = (error as Error).message || 'Ocurrió un error desconocido.';
            setMessage({ type: 'error', text: `OCURRIÓ UN ERROR:\n${errorMessage}` });
        } finally {
            setIsLoading(false);
        }
    };

    return (
        <div className="container max-w-4xl mx-auto my-5 sm:my-10 p-6 sm:p-8 bg-white rounded-xl shadow-2xl">
            <h1 className="text-3xl sm:text-4xl font-bold text-center text-pme-primary mb-8">
                Generador de Acciones PME (IA)
            </h1>

            {message && <MessageBox message={message} />}

            <div className="grid md:grid-cols-2 gap-6 mb-4">
                <div className="form-group">
                    <label htmlFor="dimension" className="block mb-2 font-bold text-pme-primary">1. Dimensión de Gestión:</label>
                    <select id="dimension" value={dimension} onChange={handleDimensionChange} className="w-full p-2 border border-gray-300 rounded-md focus:ring-pme-secondary focus:border-pme-secondary">
                        <option value="">-- Seleccione --</option>
                        {Object.keys(dataMap).map(dim => <option key={dim} value={dim}>{dim}</option>)}
                    </select>
                </div>
                <div className="form-group">
                    <label htmlFor="subdimension" className="block mb-2 font-bold text-pme-primary">2. Subdimensión:</label>
                    <select id="subdimension" value={subdimension} onChange={e => setSubdimension(e.target.value)} disabled={!dimension} className="w-full p-2 border border-gray-300 rounded-md focus:ring-pme-secondary focus:border-pme-secondary disabled:bg-gray-100">
                        <option value="">-- Seleccione Dimensión primero --</option>
                        {subdimensiones.map(sub => <option key={sub} value={sub}>{sub}</option>)}
                    </select>
                </div>
            </div>

            <div className="form-group mb-6">
                <label htmlFor="objEstrategico" className="block mb-2 font-bold text-pme-primary">3. Objetivo Estratégico (PME):</label>
                 <div className="relative">
                    <textarea 
                        id="objEstrategico" 
                        value={objEstrategico} 
                        onChange={e => setObjEstrategico(e.target.value)} 
                        placeholder="Ej: Mejorar la comprensión lectora... o presiona el botón de IA para una sugerencia." 
                        className="w-full p-2 border border-gray-300 rounded-md h-24 resize-y focus:ring-pme-secondary focus:border-pme-secondary pr-12"
                    />
                    <button
                        onClick={handleGenerateStrategicObjective}
                        disabled={isGeneratingObjective || selectedPlanes.length === 0 || !subdimension}
                        className="absolute top-2 right-2 bg-pme-accent text-white px-2 py-1 rounded-md text-xs font-bold hover:bg-orange-600 transition duration-300 disabled:bg-gray-400 disabled:cursor-not-allowed flex items-center justify-center"
                        title="Generar sugerencia con IA (selecciona subdimensión y planes primero)"
                        style={{ height: '24px', width: '30px' }}
                    >
                        {isGeneratingObjective ? <Spinner size="sm" /> : 'IA'}
                    </button>
                </div>
            </div>

            <div className="form-group mb-6">
                 <label htmlFor="estrategia" className="block mb-2 font-bold text-pme-primary">4. Estrategia PME:</label>
                 <div className="relative">
                     <textarea 
                        id="estrategia" 
                        value={estrategia} 
                        onChange={e => setEstrategia(e.target.value)} 
                        placeholder="Define la línea de acción principal o presiona el botón de IA para una sugerencia."
                        className="w-full p-2 border border-gray-300 rounded-md h-24 resize-y focus:ring-pme-secondary focus:border-pme-secondary pr-12"
                     />
                    <button
                        onClick={handleGenerateEstrategia}
                        disabled={isEstrategiaButtonDisabled}
                        className="absolute top-2 right-2 bg-pme-accent text-white px-2 py-1 rounded-md text-xs font-bold hover:bg-orange-600 transition duration-300 disabled:bg-gray-400 disabled:cursor-not-allowed flex items-center justify-center"
                        title="Generar estrategia con IA (completa los campos anteriores primero)"
                        style={{ height: '24px', width: '30px' }}
                    >
                        {isGeneratingEstrategia ? <Spinner size="sm" /> : (estrategia ? '🔄' : 'IA')}
                    </button>
                 </div>
            </div>

            <div className="form-group mb-4">
                <label className="block mb-2 font-bold text-pme-primary">5. Planes Normativos para Articular (Máximo 2):</label>
                <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4 bg-pme-light p-4 rounded-md">
                    {Object.values(Plan).map(plan => (
                        <label key={plan} className="flex items-center gap-2 text-sm text-pme-primary">
                            <input type="checkbox" name="planes" value={plan} onChange={handlePlanSelection} className="h-4 w-4 rounded border-gray-300 text-pme-secondary focus:ring-pme-secondary"/>
                            {plan}
                        </label>
                    ))}
                </div>
            </div>

            <div className="form-group mb-4">
                <label className="block mb-2 font-bold text-pme-primary">6. Objetivos Específicos por Plan Seleccionado:</label>
                <div id="objectivesContainer" className="space-y-3">
                    {selectedPlanes.length === 0 ? (
                        <p className="text-gray-500 italic">Seleccione un plan arriba para ver sus objetivos disponibles.</p>
                    ) : (
                        selectedPlanes.map(planName => (
                            <div key={planName} className="dynamic-objective-group bg-gray-50 border-l-4 border-pme-accent p-3 rounded-r-md">
                                <label className="block text-sm font-semibold text-pme-accent mb-1">{`Objetivo para: ${planName}`}</label>
                                <select 
                                    className="w-full p-2 text-sm border border-gray-300 rounded-md focus:ring-pme-secondary focus:border-pme-secondary"
                                    value={selectedPlanObjectives[planName] || ''}
                                    onChange={(e) => handleObjectiveChange(planName, e.target.value)}
                                >
                                    <option value="">-- Selecciona un objetivo --</option>
                                    {objetivosNormativos[planName as keyof typeof objetivosNormativos].map((obj, index) => (
                                        <option key={`${planName}-${index}`} value={obj}>{obj}</option>
                                    ))}
                                    <option value="Otro">Otro (Especificar manualmente...)</option>
                                </select>
                            </div>
                        ))
                    )}
                </div>
            </div>

            <div className="form-group mb-6">
                <label htmlFor="cantidad" className="block mb-2 font-bold text-pme-primary">7. Cantidad de Acciones a proponer:</label>
                <input type="number" id="cantidad" value={cantidad} onChange={e => setCantidad(parseInt(e.target.value, 10))} min="1" max="5" className="w-full md:w-1/4 p-2 border border-gray-300 rounded-md focus:ring-pme-secondary focus:border-pme-secondary"/>
            </div>

            <button onClick={generarPropuesta} disabled={isLoading} className="w-full bg-pme-secondary text-white py-3 px-6 rounded-md text-lg font-semibold hover:bg-blue-600 transition duration-300 disabled:bg-gray-400 disabled:cursor-not-allowed flex items-center justify-center gap-3">
                {isLoading && <Spinner />}
                {isLoading ? 'Generando Propuestas...' : (result ? 'Regenerar Propuesta' : 'Generar Propuestas con IA')}
            </button>

            {result && (
                 <div id="resultArea" className="mt-8 p-6 border border-gray-200 rounded-lg bg-white shadow-inner">
                    <div dangerouslySetInnerHTML={{ __html: result }} />
                </div>
            )}
        </div>
    );
}

