        | :--- | :--- |
        | **Objetivo Estratégico** | ${objEstrategico} |
        | **Meta Estratégica** | [Genera aquí una meta SMART y concisa vinculada al objetivo] |
        | **Estrategia** | ${estrategia} |
        | **Subdimensión** | ${subdimension} |

        ## Seguimiento a la Estrategia
        | Nombre Indicador | Descripción Indicador |
        | :--- | :--- |
        | [Genera aquí el nombre del indicador 1] | [Genera aquí la descripción del indicador 1] |
        | [Genera aquí el nombre del indicador 2] | [Genera aquí la descripción del indicador 2] |

        ## Acciones Propuestas
        ${actionBlocks}
        --- FIN DE LA PLANTILLA ---
    `;

    let lastError: Error | null = null;

    for (const modelName of modelsToTry) {
        try {
            console.log(`Intentando conectar con modelo: ${modelName}`);
            const response: GenerateContentResponse = await ai.models.generateContent({
                model: modelName,
                contents: [{ parts: [{ text: promptText }] }],
                // Safety settings to prevent blocking for educational topics like sexuality
                safetySettings: [
                    { category: "HARM_CATEGORY_HARASSMENT", threshold: "BLOCK_ONLY_HIGH" },
                    { category: "HARM_CATEGORY_HATE_SPEECH", threshold: "BLOCK_ONLY_HIGH" },
                    { category: "HARM_CATEGORY_SEXUALLY_EXPLICIT", threshold: "BLOCK_ONLY_HIGH" },
                    { category: "HARM_CATEGORY_DANGEROUS_CONTENT", threshold: "BLOCK_ONLY_HIGH" }
                ]
            });

            const text = response.text;
            if (text) {
                console.log(`Éxito con modelo: ${modelName}`);
                return text;
            }

            // Handle cases where the response is empty or blocked
            const finishReason = response.candidates?.[0]?.finishReason;
            if (finishReason === 'SAFETY') {
                throw new Error("La respuesta fue bloqueada por filtros de seguridad. Intenta reformular el objetivo evitando términos muy explícitos.");
            }
             if (finishReason === 'RECITATION') {
                throw new Error("La respuesta fue bloqueada por ser similar a una fuente protegida. Intenta reformular el objetivo.");
            }

            throw new Error('La IA devolvió una respuesta vacía.');

        } catch (error) {
            console.error(`Error con el modelo ${modelName}:`, error);
            lastError = error as Error;
        }
    }

    if (lastError?.message.includes('API key not valid')) {
       throw new Error("ERROR DE API KEY: La clave de API no es válida. Por favor, asegúrate de que esté configurada correctamente.");
    }

    if (lastError?.message.includes('permission')) {
         throw new Error("ERROR DE PERMISOS: La clave de API no tiene los permisos necesarios. Verifica que la 'Generative Language API' esté habilitada en tu proyecto de Google Cloud.");
    }

    throw lastError || new Error("Todos los modelos de IA fallaron. Por favor, inténtalo de nuevo más tarde.");
};

import React, { useState, useMemo } from 'react';
import { dataMap, objetivosNormativos, Plan } from './constants';
