interface ImageResult {
    imageUrl: string | null;
    text: string | null;
}

export default function ImageGenerator() {
    const [prompt, setPrompt] = useState<string>('');
    const [aspectRatio, setAspectRatio] = useState<string>('1:1');
    const [isLoading, setIsLoading] = useState<boolean>(false);
    const [result, setResult] = useState<ImageResult | null>(null);
    const [message, setMessage] = useState<Message | null>(null);

    const aspectRatios = ["1:1", "16:9", "9:16", "4:3", "3:4"];

    const handleGenerate = async () => {
        if (!prompt) {
            setMessage({ type: 'error', text: 'Por favor, introduce un prompt para generar la imagen.' });
            return;
        }
        setIsLoading(true);
        setMessage(null);
        setResult(null);
        try {
            const imageResult = await generateImage(prompt, aspectRatio);
            setResult(imageResult);
        } catch (error) {
            const errorMessage = (error as Error).message || 'Ocurrió un error desconocido.';
            setMessage({ type: 'error', text: `Error al generar la imagen: ${errorMessage}` });
        } finally {
            setIsLoading(false);
        }
    };

    return (
        <div className="p-6 sm:p-8">
            <h1 className="text-3xl sm:text-4xl font-bold text-center text-pme-primary mb-2">
                Generador de Imágenes con IA
            </h1>
            <p className="text-center text-gray-500 mb-8">Crea imágenes a partir de descripciones de texto.</p>

            {message && <MessageBox message={message} />}

            <div className="space-y-4">
                <div>
                    <label htmlFor="prompt" className="block mb-2 font-bold text-pme-primary">Prompt:</label>
                    <textarea
                        id="prompt"
                        value={prompt}
                        onChange={(e) => setPrompt(e.target.value)}
                        placeholder="Ej: Un astronauta montando a caballo en Marte, estilo fotorrealista."
                        className="w-full p-2 border border-gray-300 rounded-md h-24 resize-y focus:ring-pme-secondary focus:border-pme-secondary"
                    />
                </div>
                <div>
                    <label htmlFor="aspectRatio" className="block mb-2 font-bold text-pme-primary">Relación de Aspecto:</label>
                    <select
                        id="aspectRatio"
                        value={aspectRatio}
                        onChange={(e) => setAspectRatio(e.target.value)}
                        className="w-full md:w-1/2 p-2 border border-gray-300 rounded-md focus:ring-pme-secondary focus:border-pme-secondary"
                    >
                        {aspectRatios.map(ar => <option key={ar} value={ar}>{ar}</option>)}
                    </select>
                </div>
            </div>

            <button onClick={handleGenerate} disabled={isLoading} className="w-full mt-6 bg-pme-secondary text-white py-3 px-6 rounded-md text-lg font-semibold hover:bg-blue-600 transition duration-300 disabled:bg-gray-400 flex items-center justify-center gap-3">
                {isLoading ? <Spinner /> : <span className="material-symbols-outlined">auto_awesome</span>}
                {isLoading ? 'Generando...' : 'Generar Imagen'}
            </button>

            {result && result.imageUrl && (
                <div className="mt-8 border border-gray-300 rounded-lg bg-white shadow-inner overflow-hidden p-4">
                    <h2 className="text-xl font-semibold text-pme-primary mb-4">Resultado:</h2>
                    <div className="flex justify-center bg-gray-100 p-4 rounded-md">
                        <img src={result.imageUrl} alt={prompt} className="max-w-full max-h-96 rounded-md shadow-md" />
                    </div>
                    {result.text && <p className="mt-4 text-gray-700 italic">{result.text}</p>}
                </div>
            )}
        </div>
    );
}

import React, { useState, useEffect, useRef } from 'react';
import { GoogleGenAI, Chat } from '@google/genai';
import type { ChatMessage } from '../types';
import Spinner from './Spinner';

interface ChatbotProps {
    onClose: () => void;
}

// Initialize the GoogleGenAI client
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export default function Chatbot({ onClose }: ChatbotProps) {
    const [chat, setChat] = useState<Chat | null>(null);
    const [history, setHistory] = useState<ChatMessage[]>([]);
    const [userInput, setUserInput] = useState<string>('');
    const [isLoading, setIsLoading] = useState<boolean>(false);
    const chatContainerRef = useRef<HTMLDivElement>(null);

    useEffect(() => {
        const initChat = () => {
            const chatInstance = ai.chats.create({
                model: 'gemini-3-pro-preview',
                config: {
                    systemInstruction: 'Eres un asistente experto en educación y en el sistema PME de Chile. Responde las preguntas de los usuarios de forma concisa y útil.',
                },
            });
            setChat(chatInstance);
        };
        initChat();
    }, []);

    useEffect(() => {
        // Scroll to the bottom of the chat on new messages
        if (chatContainerRef.current) {
            chatContainerRef.current.scrollTop = chatContainerRef.current.scrollHeight;
        }
    }, [history]);

    const handleSendMessage = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!userInput.trim() || !chat || isLoading) return;

        const userMessage: ChatMessage = { role: 'user', parts: [{ text: userInput }] };
        setHistory(prev => [...prev, userMessage]);
        setUserInput('');
        setIsLoading(true);

        try {
            const stream = await chat.sendMessageStream({ message: userInput });

            let modelResponse = '';
            setHistory(prev => [...prev, { role: 'model', parts: [{ text: '' }] }]);

            for await (const chunk of stream) {
                const c = chunk as any;
                modelResponse += c.text;
                setHistory(prev => {
                    const newHistory = [...prev];
                    newHistory[newHistory.length - 1] = { role: 'model', parts: [{ text: modelResponse }] };
                    return newHistory;
                });
            }
        } catch (error) {
            console.error(error);
            setHistory(prev => [...prev, { role: 'model', parts: [{ text: 'Lo siento, ha ocurrido un error. Inténtalo de nuevo.' }] }]);
        } finally {
            setIsLoading(false);
        }
    };

    const MessageBubble = ({ message }: { message: ChatMessage }) => {
        const isUser = message.role === 'user';
        const bubbleClasses = isUser
            ? 'bg-pme-secondary text-white self-end'
            : 'bg-pme-light text-pme-primary self-start';
        return (
            <div className={`max-w-xs md:max-w-md p-3 rounded-xl ${bubbleClasses}`}>
                <p className="text-sm whitespace-pre-wrap">{message.parts[0].text}</p>
            </div>
        );
    };

    return (
        <div className="fixed bottom-24 right-6 w-80 md:w-96 h-[60vh] bg-white rounded-2xl shadow-2xl flex flex-col z-40">
            <header className="flex items-center justify-between p-4 bg-pme-primary text-white rounded-t-2xl">
                <h3 className="font-bold text-lg">Asistente IA</h3>
                <button onClick={onClose} className="hover:bg-black/20 rounded-full p-1">
                    <span className="material-symbols-outlined">close</span>
                </button>
            </header>

            <div ref={chatContainerRef} className="flex-1 p-4 space-y-4 overflow-y-auto">
                 {history.map((msg, index) => <MessageBubble key={index} message={msg} />)}
                 {isLoading && (
                    <div className="self-start flex items-center gap-2">
                        <Spinner size="sm" />
                        <span className="text-sm text-gray-500">Pensando...</span>
                    </div>
                 )}
            </div>

            <form onSubmit={handleSendMessage} className="p-4 border-t border-gray-200">
                <div className="relative">
                    <input
                        type="text"
                        value={userInput}
                        onChange={(e) => setUserInput(e.target.value)}
                        placeholder="Haz una pregunta..."
                        className="w-full p-2 pr-10 border border-gray-300 rounded-full focus:ring-pme-secondary focus:border-pme-secondary"
                        disabled={isLoading}
                    />
                    <button type="submit" disabled={isLoading || !userInput.trim()} className="absolute top-1/2 right-2 -translate-y-1/2 bg-pme-secondary text-white rounded-full p-1.5 disabled:bg-gray-400 hover:bg-blue-600 transition">
                         <span className="material-symbols-outlined">send</span>
                    </button>
                </div>
            </form>
        </div>
    );
}

import React, { useState } from 'react';
import PmeGenerator from './components/PmeGenerator';
import ImageGenerator from './components/ImageGenerator';
import Chatbot from './components/Chatbot';

type Tab = 'pme' | 'image';

export default function App() {
    const [activeTab, setActiveTab] = useState<Tab>('pme');
    const [isChatOpen, setIsChatOpen] = useState<boolean>(false);

    // FIX: Re-typed component props using React.FC to resolve incorrect 'children' prop error.
    const TabButton: React.FC<{ tabId: Tab, currentTab: Tab, setTab: (tab: Tab) => void, icon: string, children: React.ReactNode }> = ({ tabId, currentTab, setTab, icon, children }) => (
        <button
            onClick={() => setTab(tabId)}
            className={`flex items-center justify-center gap-2 px-4 py-2 text-sm font-medium rounded-t-lg transition-all duration-300 focus:outline-none focus:ring-2 focus:ring-pme-secondary focus:ring-offset-2 ${
                currentTab === tabId
                    ? 'bg-white text-pme-primary border-b-2 border-pme-secondary'
                    : 'bg-gray-100 text-gray-500 hover:bg-gray-200'
            }`}
        >
            <span className="material-symbols-outlined">{icon}</span>
            {children}
        </button>
    );

    return (
        <div className="container max-w-4xl mx-auto my-5 sm:my-10">
            <div className="flex border-b border-gray-200">
                <TabButton tabId="pme" currentTab={activeTab} setTab={setActiveTab} icon="description">Generador PME</TabButton>
                <TabButton tabId="image" currentTab={activeTab} setTab={setActiveTab} icon="image">Generador de Imágenes</TabButton>
            </div>

            <div className="bg-white rounded-b-xl shadow-2xl overflow-hidden">
                {activeTab === 'pme' && <PmeGenerator />}
                {activeTab === 'image' && <ImageGenerator />}
            </div>

            {/* Chatbot and FAB */}
            <div className="fixed bottom-6 right-6 z-50">
                <button
                    onClick={() => setIsChatOpen(!isChatOpen)}
                    className="bg-pme-secondary text-white rounded-full p-4 shadow-lg hover:bg-blue-600 focus:outline-none focus:ring-2 focus:ring-pme-secondary focus:ring-offset-2 transition-transform duration-300 hover:scale-110"
                    aria-label="Abrir chat de ayuda"
                >
                    <span className="material-symbols-outlined">smart_toy</span>
                </button>
            </div>

            {isChatOpen && <Chatbot onClose={() => setIsChatOpen(false)} />}
        </div>
    );
}

